import org.apache.nifi.serialization.record.MapRecord
import java.util.LinkedHashMap

// ============================================================================
// HTML 제거 유틸
// ============================================================================

static String stripHtml(String s) {
    if (s == null) return null

    return s
        .replaceAll(/(?is)<script[^>]*>.*?<\/script>/, " ")
        .replaceAll(/(?is)<style[^>]*>.*?<\/style>/, " ")
        .replaceAll(/<!--[\s\S]*?-->/, " ")
        .replaceAll(/<[^>]*>/, " ")
        .replaceAll(/(?i)&nbsp;/, " ")
        .replaceAll(/(?i)&amp;/, "&")
        .replaceAll(/(?i)&lt;/, "<")
        .replaceAll(/(?i)&gt;/, ">")
        .replaceAll(/(?i)&quot;/, "\"")
        .replaceAll(/(?i)&#0?39;/, "'")
        .replaceAll(/(?i)&apos;/, "'")
        .replaceAll(/\s+/, " ")
        .trim()
}

// ============================================================================
// 메인 변환 로직
// ============================================================================

// 기존 스키마 그대로 사용
def schema = record.getSchema()

// Record를 mutable Map으로 복사
def m = new LinkedHashMap<String, Object>(record.toMap())

// content 필드: HTML 제거
if (m.containsKey("content") && m.get("content") != null) {
    m.put("content", stripHtml(m.get("content") as String))
}

// 변환된 Record 반환
return new MapRecord(schema, m)

import groovy.json.JsonSlurper
import groovy.json.JsonOutput
import org.apache.nifi.processor.io.StreamCallback
import java.nio.charset.StandardCharsets

flowFile = session.get()
if (!flowFile) return

flowFile = session.write(flowFile, { inputStream, outputStream ->
    // JSON 파싱
    def text = inputStream.getText('UTF-8')
    def json = new JsonSlurper().parseText(text)

    // json이 리스트(RecordSet)라고 가정
    json.each { record ->
        if (record.id != null) {
            record.id = record.id.toString() // 숫자 -> 문자열
        }
    }

    // 다시 JSON으로 쓰기
    outputStream.write(JsonOutput.toJson(json).getBytes(StandardCharsets.UTF_8))
} as StreamCallback)

session.transfer(flowFile, REL_SUCCESS)

import org.apache.nifi.processor.io.StreamCallback
import java.nio.charset.StandardCharsets

flowFile = session.get()
if (!flowFile) return

flowFile = session.write(flowFile, { inputStream, outputStream ->
    def reader = recordReaderFactory.createRecordReader(inputStream, flowFile, session)
    def writer = recordWriterFactory.createWriter(session, flowFile, reader.getSchema(), outputStream)

    def record
    while ((record = reader.nextRecord()) != null) {
        // id 필드가 null이 아니면 string으로 변환
        if (record.getValue("id") != null) {
            record.setValue("id", record.getValue("id").toString())
        }
        writer.write(record)
    }

    writer.close()
    reader.close()
} as StreamCallback)

session.transfer(flowFile, REL_SUCCESS)

def removeHtmlTags(String html) {
      if (html == null) return null

      // script, style 태그와 내용 통째로 제거
      def result = html.replaceAll("(?si)<script[^>]*>.*?</script>", " ")
      result = result.replaceAll("(?si)<style[^>]*>.*?</style>", " ")

      // 나머지 HTML 태그 제거
      result = result.replaceAll("(?s)<[^>]*>", " ")

      // HTML 엔티티 제거 (&amp; &lt; 등)
      result = result.replaceAll("&[^;]+;", " ")

      // 공백 정리
      result = result.replaceAll("\\s+", " ").trim()

      return result
  }

  def content = record.getValue("content")

  if (content != null) {
      record.setValue("content_html", content)
      record.setValue("content", removeHtmlTags(content.toString()))
  }

  return record
